import { DashboardLayout, Sidebar, Topbar, NavItem } from '@keter-ui/react';
import { useRTL } from '@keter-ui/rtl';
import { useToggle } from '@keter-ui/core';

export function Dashboard({ children }) {
  const { isRTL, toggleDirection } = useRTL();
  const [collapsed, toggle] = useToggle(false);

  return (
    <DashboardLayout
      sidebar={
        <Sidebar collapsed={collapsed}>
          <NavItem label="Dashboard" icon="⊞" active />
          <NavItem label="Users" icon="👤" />
        </Sidebar>
      }
      topbar={
        <Topbar>
          <button onClick={toggleDirection}>{isRTL ? 'LTR' : 'RTL'}</button>
        </Topbar>
      }
    >
      {children}
    </DashboardLayout>
  );
}

import { ThemeProvider, useThemeContext } from '@keter-ui/react';

function App() {
  return (
    <ThemeProvider defaultTheme="system">
      <Layout />
    </ThemeProvider>
  );
}

function ThemeToggle() {
  const { resolvedTheme, toggleTheme } = useThemeContext();
  return (
    <button onClick={toggleTheme}>
      {resolvedTheme === 'dark' ? '☀️ Light' : '🌙 Dark'}
    </button>
  );
}

import { Table } from '@keter-ui/react';

interface User { id: number; name: string; email: string; }

const columns = [
  { key: 'id' as const, header: 'ID', sortable: true },
  { key: 'name' as const, header: 'Name', sortable: true },
  { key: 'email' as const, header: 'Email' },
];

const data: User[] = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

export function UserTable() {
  return <Table columns={columns} data={data} />;
}
